const payload = $input.item.json;
const root = payload?.data ?? payload;

function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return null;
}

function toAbsoluteUrl(url) {
  if (!url || typeof url !== 'string') return null;
  if (url.startsWith('http://') || url.startsWith('https://')) return url;
  if (url.startsWith('//')) return `https:${url}`;
  if (url.startsWith('/')) return `https://www.americanas.com.br${url}`;
  return `https://www.americanas.com.br/${url.slice(1)}`;
}

function toImageUrl(node) {
  const image = node.image || node.imageUrl || node.thumbnail || node.media || node.pictures;
  if (typeof image === 'string') return toAbsoluteUrl(image);
  if (Array.isArray(image) && image.length > 0) {
    const first = image[0];
    if (typeof first === 'string') return toAbsoluteUrl(first);
    if (first && typeof first === 'object') return toAbsoluteUrl(first.url || first.src || first.imageUrl || first.thumb);
  }
  if (image && typeof image === 'object') {
    return toAbsoluteUrl(image.url || image.src || image.imageUrl || image.thumb);
  }
  return null;
}

function resolvePrice(node) {
  const candidates = [
    node.salePrice,
    node.price,
    node.listPrice,
    node.offerPrice,
    node.currentPrice,
    node.lowPrice,
    node.highPrice,
    node.offers?.price,
    node.offers?.lowPrice,
    node.offers?.highPrice,
    node.priceRange?.sellingPrice?.lowPrice,
    node.priceRange?.sellingPrice?.highPrice,
    node.priceRange?.listPrice?.lowPrice,
    node.priceRange?.listPrice?.highPrice,
  ];

  for (const value of candidates) {
    const numeric = typeof value === 'number' ? value : Number(value);
    if (Number.isFinite(numeric) && numeric > 0) return numeric;
  }

  return null;
}

function resolveFreeShipping(node) {
  const candidates = [
    node.free_shipping,
    node.freeShipping,
    node.hasFreeShipping,
    node.shipping?.free,
    node.shipping?.freeShipping,
    node.shippingInfo?.freeShipping,
    node.logistics?.freeShipping,
  ];

  for (const value of candidates) {
    if (typeof value === 'boolean') return value;
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (['true', 'sim', 'yes'].includes(normalized)) return true;
      if (['false', 'nao', 'não', 'no'].includes(normalized)) return false;
    }
  }

  return null;
}

function normalizeProduct(node) {
  const title = firstString(node.name, node.title, node.productName, node.shortName);
  if (!title) return null;

  const link = toAbsoluteUrl(node.url || node.href || node.link || node.slug || node.productUrl || node.canonicalUrl);
  const price = resolvePrice(node);
  const image = toImageUrl(node);
  const brand = firstString(node.brand?.name, node.brand, node.manufacturer, node.seller?.name);
  const sku = firstString(node.sku, node.id, node.productId, node.referenceId, node.itemId);
  const freeShipping = resolveFreeShipping(node);

  return {
    title,
    product_page_url: link,
    link,
    image,
    sku,
    brand,
    source: 'americanas',
    source_name: 'Americanas',
    price_cash: price,
    price_cash_formatted: price ? `R$ ${price.toFixed(2).replace('.', ',')}` : null,
    free_shipping: freeShipping,
    shipping_note: freeShipping === true ? 'Frete grátis' : freeShipping === false ? 'Frete não informado' : 'Consulte o frete no link',
  };
}

function walk(node, acc, seen) {
  if (!node || typeof node !== 'object') return;
  if (seen.has(node)) return;
  seen.add(node);

  if (Array.isArray(node)) {
    for (const item of node) walk(item, acc, seen);
    return;
  }

  if (node.node && typeof node.node === 'object') {
    walk(node.node, acc, seen);
  }

  const hasName = typeof node.name === 'string' || typeof node.title === 'string' || typeof node.productName === 'string';
  const hasCommercialData = node.price != null || node.salePrice != null || node.listPrice != null || node.priceRange || node.offers || node.images || node.image || node.url || node.href || node.slug || node.link;

  if (hasName && hasCommercialData) {
    acc.push(node);
  }

  for (const value of Object.values(node)) {
    walk(value, acc, seen);
  }
}

const collected = [];
walk(root, collected, new Set());

const normalized = [];
const dedupe = new Set();
for (const candidate of collected) {
  const product = normalizeProduct(candidate);
  if (!product) continue;
  const key = `${product.title}|${product.product_page_url || ''}|${product.sku || ''}`;
  if (dedupe.has(key)) continue;
  dedupe.add(key);
  normalized.push(product);
}

normalized.sort((a, b) => {
  const priceA = Number.isFinite(a.price_cash) ? a.price_cash : Number.POSITIVE_INFINITY;
  const priceB = Number.isFinite(b.price_cash) ? b.price_cash : Number.POSITIVE_INFINITY;
  return priceA - priceB;
});

const searchTerm = payload?.variables?.term || payload?.data?.search?.term || payload?.data?.search?.query || payload?.term || 'Não identificado';
const hasErrors = Array.isArray(payload?.errors) && payload.errors.length > 0;

return [{
  json: {
    products: normalized,
    total_products_found: normalized.length,
    search_term: searchTerm,
    source: 'americanas',
    source_name: 'Americanas',
    source_status: hasErrors ? 'blocked' : 'ok',
    source_notes: hasErrors ? 'GraphQL respondeu com erro; valide cookie e CSRF funcionais do navegador.' : 'Consulta GraphQL extraída do DevTools.',
    extracted_at: new Date().toISOString(),
  }
}];
